onClick:
{{(() => {
  const dados = relatorio_tickets.data || [];
  if (!dados.length) {
    showAlert('Gere o relatório antes de exportar.', 'warning');
    return;
  }

  // Limitação do Appsmith nativo: sem gerador XLSX binário embutido.
  // Estratégia estável: gerar arquivo .xls (HTML tabular) compatível com Excel.
  const colunas = Object.keys(dados[0]);
  const esc = (v) => String(v ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const header = `<tr>${colunas.map(c => `<th>${esc(c)}</th>`).join('')}</tr>`;
  const rows = dados.map(row => `<tr>${colunas.map(c => `<td>${esc(row[c])}</td>`).join('')}</tr>`).join('');
  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body><table border="1">${header}${rows}</table></body></html>`;
  const arquivo = `relatorio_tickets_${moment().format('YYYYMMDD_HHmm')}.xls`;
  download(html, arquivo, 'application/vnd.ms-excel');
  showAlert('Exportação Excel compatível concluída (.xls).', 'success');
})();}}
